var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이봐, 신부님! 필립 신부님!","JPN":"おい、神父！　フィリップ神父！","ENG":"Father! Father Philip!","TWN":"喂，神父！菲力浦神父！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어디 갔어, 이 영감님......? 또 낚시 하러 나갔나?","JPN":"どこ行ったんだ、あのジジイ……？　また釣りか？","ENG":"Where is the old fool? Did he go fishing again?","TWN":"去哪裡了，這老先生……？又去釣魚了嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아, 필립 신부님은 급한 용무 때문에 잠시 자리를 비우셨어요.","JPN":"あら、フィリップ神父は急用で不在ですが。","ENG":"Oh, Father Philip had to tend to an urgent matter.","TWN":"啊，菲力浦神父有急事，暫時離開了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"급한 용무?","JPN":"急用？","ENG":"Urgent matter?","TWN":"急事？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하아...... 그 영감님 또 낚싯대 고치러 가셨구만.","JPN":"はあ……あのジジイ、また釣竿を直しに行ったのか。","ENG":"*Sigh* He probably went to fix his fishing rod again.","TWN":"哈啊……看來那老頭又去修理釣魚竿了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 댁들은 누구야? 여긴 촌동네라 수녀님들은 그 동안 없었는데?","JPN":"ところで、お前らは誰だ？　ここに修道女はいなかったはずだが？","ENG":"Who are you lot, by the way? I thought they never sent sisters out to the middle of nowhere like this.","TWN":"不過你們是誰？這裡是小鄉下，可沒有修女吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아, 네. 저희는 사람을 찾느라 필립 신부님께 여쭤 볼 게 있어서......","JPN":"はい。私たちは人を探しておりまして、フィリップ神父に話を伺いに……","ENG":"Oh, right. We're looking for someone, and wanted to ask Father Philip about this person...","TWN":"啊，我們是來找人的，有些事情想問問菲力浦神父……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"뭘 또 주절주절 설명하고 있어. 서로 볼일 없는 사람들끼리.","JPN":"説明しなくてもいいだろ。どうせこの先、会うこともないんだ。","ENG":"What are you explaining it all to him for? It's none of his beeswax.","TWN":"跟一個不相干的人說那麼多做什麼。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"총각. 우리한텐 신경 끄고 댁 갈 길이나 가셔.","JPN":"お兄さん、アタシたちのことは気にせずに、とっとと消えな。","ENG":"Listen, young fella. Why don't you mind your on business and be on your way?","TWN":"小夥子，別管我們的事，走你的路吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 이 꼬맹이가......?","JPN":"はあ？　何だ、このガキ……？","ENG":"What? Why you little twerp...","TWN":"什麼？妳這個小不點……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"어쭈, 꼬맹이?","JPN":"へえ、ガキ？","ENG":"Ha, little twerp?","TWN":"唉唷，小不點 ？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그 꼬맹이한테 볼기짝 좀 맞아 볼래? 3초 안에 할렐루야 복창이 절로 나올 텐데?","JPN":"そのガキにお尻ぺんぺんでも食らってみる？\\n3秒以内に、神様に泣きつきたくなると思うけど？","ENG":"How'd you like to get your butt kicked by a little twerp? I'll have you singing hallelujah within three seconds, I guarantee you!","TWN":"想嘗嘗我這個小不點的厲害嗎？我會讓你不到3秒就會跪地求饒喔？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님! 그런 나쁜 말 쓰면 안 돼요!","JPN":"シスター・シンディ！　そんな汚い言葉を使ってはいけません！","ENG":"Sister Cindy! Please watch your mouth!","TWN":"姊妹！你可不能說這種粗魯的話！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"죄송합니다. 저희 자매님이 말씀이 조금 거칠어요.","JPN":"ごめんなさい。妹の言葉遣いが少々荒くて……","ENG":"Apologies. Sister Cindy here can be a little rough with her words.","TWN":"對不起，我們姊妹講話有點粗魯。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......조금?","JPN":"……少々？","ENG":"A little?","TWN":"……有點？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"예전보단 많이 나아지셨어요. 모두 자비로우신 주님 덕분이죠.","JPN":"これでも以前よりは良くなったんです。すべては慈しみ深い神様のおかげです。","ENG":"Trust me, this is a big improvement. All thanks to the Lord's grace and mercy.","TWN":"比以前好很多了，這都是因為主的慈悲。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"쳇. 이 언니는 뭐만 하면 다 자비래.","JPN":"チッ。この姉さんは何でもかんでも慈しみって言うんだから。","ENG":"Hmpf. There you go with the grace and mercy crap again.","TWN":"切，姐姐不管什麼事都說是慈悲。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매니임!","JPN":"シスター・シンディ！","ENG":"Sister Cindy!","TWN":"姊妹！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"혹시 필립 신부님께 도움을 청하러 오셨다면, 저희가 대신 도와드릴 수 있어요.","JPN":"もしフィリップ神父にご用でしたら、私たちが代わりにお役に立てると思います。","ENG":"If you're here to ask Father Philip for help, we may be able to help you instead.","TWN":"如果你是來找菲力浦神父幫忙的話，我們也可以幫你的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"에이, 또 오지랖이야.","JPN":"またそうやって余計なことに首を突っ込む。","ENG":"Ugh, why do you have to go out of your way to help everyone all the time?","TWN":"哎呀，又多管閒事了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"고맙지만 됐어. 다른 사람한테 이야기 할 만한 일이 아니거든.","JPN":"ありがたいけど、結構だ。他の人に話すようなことじゃないし。","ENG":"Thanks, but it's okay. It's not exactly something I can share with anyone else.","TWN":"謝謝妳的好意，不過不用了。這件事不能跟其他人說。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나중에 신부님한테 얘기나 전해 줘. 로이 버넷이 물어볼 게 있어서 왔다고.","JPN":"あとで神父に伝えておいてくれ。ロイ・バーネットが、聞きたいことがあるってな。","ENG":"Please just let the father know I was looking for him. Tell him that Roy Burnett came to ask him something.","TWN":"麻煩給神父帶個口信，就說羅伊·伯內特有事要問他。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네? 혹시 버넷 경이란 분의 손자신가요?","JPN":"あら？　もしかして、バーネット卿という方のお孫さんですか？","ENG":"Huh? Are you by any chance the grandson of Sir Burnett?","TWN":"啊？莫非你是伯內特卿的孫子？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야? 당신들도 우리 할아버지를 알아?","JPN":"何だ？　お前らもじいさんのことを知ってるのか？","ENG":"What? You know about my grandfather?","TWN":"怎麼？你們也認識我爺爺？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네. 그 분이 사람을 찾는 데 전문이라는 이야기를 듣고 왔어요.","JPN":"はい。その方が人探しのプロだという話を聞いたもので。","ENG":"Yes. We came here because we heard he could track down anyone you're looking for.","TWN":"是，我們聽說他是找人方面的專家才趕過來的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그런데 막상 와 보니 교회 뒤편에 그 분 묘지가 있더라고요.","JPN":"ですが、いざ来てみれば教会の裏にそのお方のお墓がありました。","ENG":"But when we got here, we saw his tombstone in the chapel's cemetery.","TWN":"不過來到這裡後就在教堂後面發現了他的墳墓。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 원...... 이제는 성당에서도 찾는 거야? 예전에 대체 뭘 하고 다녔던 거야?","JPN":"ったく……教会でも探してるってどういうことだ？　一体昔、何をしてたんだよ。","ENG":"Oh, cripes... Now even the Church is looking for him? What had he been doing when he was alive?","TWN":"真是的……現在連教堂的人也找來了？他到底以前做了什麼啊？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"어라? 혹시 저희 말고도 버넷 경을 찾는 분이 계셨나요?","JPN":"あら？　私たちの他にも、バーネット卿を探してる人がいるんですか？","ENG":"Huh? You mean someone else was looking for Sir Burnett as well?","TWN":"咦？難道除了我們，還有別人也在找伯內特卿嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나도 할아버지에 대해선 잘 몰라.","JPN":"俺もじいさんのことはよく知らないんだ。","ENG":"I don't know much about Grandpa.","TWN":"我對爺爺的事不是很了解。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 모르게 됐다고 해야 하나.","JPN":"いや、昔はよく知ってると思ってたけど、今は違う。","ENG":"Or I guess you could say I've come to realize I don't know him.","TWN":"不，應該說是根本不了解才對。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"예전에는 그냥 낚시에 빠져 사는 세상에서 제일 평범한 노인인 줄 알았거든.","JPN":"ただの釣り好きな、普通のじいさんだと思ってたんだ。","ENG":"I used to think he was just an ordinary old man who loved to fish.","TWN":"因為我一直認為他是一個沉浸在釣魚世界裡，一個最平凡的老人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 최근에...... 할아버지가 소싯적에 좀 특별한 친구들이 있었다는 말을 들었거든.","JPN":"だけど、最近……じいさんに特別な友人がいたって話を聞いてな。","ENG":"But then recently... I came to learn that he had rather special friends when he was younger.","TWN":"但最近……我聽說了爺爺年輕時有一些特別的朋友。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아무래도 믿기지 않아서 할아버지랑 낚시 친구였던 분한테 물어 보러 온 거였는데......","JPN":"どうも信じられなくて、釣り仲間だった神父に聞きに来たんだ。","ENG":"I had trouble believing the story, so I came to verify with his old fishing partner...","TWN":"因為我實在是無法相信，就想問一問跟爺爺一起釣魚的朋友，於是就來了這裡……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"혓바닥이 길다. 짧게 말해.","JPN":"話が長い。短くまとめて。","ENG":"Blah, blah, blah. Boring. Cut to the chase.","TWN":"真是廢話連篇，講重點。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어휴, 이 쪼그만한 게......","JPN":"はあ、このガキが……","ENG":"You little brat...","TWN":"唉哟，你這個小不點……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내가 알던 그 할아버지가 맞나 헷갈려서 왔다. 됐냐?","JPN":"じいさんのことが知りたくて来たんだ。これでいいか？","ENG":"I'm here to confirm if that's who my grandfather really was. Alright?","TWN":"他們說的和我印象中的爺爺完全不一樣，所以過來確認一下，這樣行了吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아, 그런 거라면 저희도 조금은 도와 드릴 수 있을 거 같아요.","JPN":"そういうことでしたら、私たちがお役に立てると思います。","ENG":"Oh, we may be able to assist you with that.","TWN":"啊，如果是這樣，我們應該也可以幫上一點忙。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어? 그래?","JPN":"え？　本当か？","ENG":"Huh? Really?","TWN":"哦？是嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네. 저희와 협력해서 사건을 해결한 적도 몇 번 있으시거든요. 대표적으로......","JPN":"はい。私たちと協力して、いくつかの事件を解決したことがあるんです。\\n代表的な事件は……","ENG":"Yes. Sir Burnett actually solved a few cases with us before. Namely...","TWN":"是的，他跟我們合作過幾次。其中代表性的……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그만해, 좀. 물에 빠뜨리면 입만 동동 뜨겠어.","JPN":"いい加減にして。口の軽い女は嫌われるよ。","ENG":"That's enough already. You lot are talking so much you'll make my ears bleed.","TWN":"好啦，別說了啦。囉哩八嗦，沒完沒了的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"놈팡이. 네가 들을 만한 얘기 아냐. 관심 끊고 살아.","JPN":"あんたには関係ない話だから、さっさと帰りな。","ENG":"Listen, Prince Charming. This ain't no story for the likes of you. You're better off in the dark, 'aight?","TWN":"小混混，這些不是你該聽的，最好不要對這些事情有興趣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야, 꼬맹이. 기어오르지 말고 얌전히 있어.","JPN":"おい、ガキ。いい加減にしろ。","ENG":"Hey, kid. Stop being so cheeky and stay put.","TWN":"喂，小不點，不要沒大沒小，給我乖乖待在旁邊玩沙。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"네 언니가 오냐 오냐 해 주니까 그러나 본데, 사회생활에선 그런 거 안 통해.","JPN":"そこのお姉さんに礼儀を教わらなかったのか？\\nお前みたいな態度、社会では通用しないぜ？","ENG":"Maybe the lady here's been spoiling you, but you can't treat people like that outside the nunnery.","TWN":"想來妳被妳姐姐慣得無法無天了，不過別人可不會吃妳這一套。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"세계 최대급 글로벌 조직의 정직원한테 사회생활 운운하고 앉았네.","JPN":"世界最大級のグローバル組織の正社員に向かって、礼儀作法を語るわけ？","ENG":"Nunnery? You're talking to a full-time employee of the world's largest global organization here.","TWN":"竟敢對全球最大跨國組織的正式員工說教。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그러는 너야말로 책임질 만한 일을 맡아 본 적은 있어?","JPN":"そういうあんたは自分がしたことに対して責任を取ったこと、ある？","ENG":"How about you, Hamlet? Have you ever taken responsibility for anything all your life?","TWN":"那你呢，你做過什麼大事嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"뭔가 책임져 본 적도 없는 애송이한테 꼬치꼬치 알려 줄 만큼 사회생활이 호락호락하진 않거든?","JPN":"責任の重さも知らないようなひよっこに、手取り足取り教えてやるほど世の中は甘くないんだ。","ENG":"I don't got time to teach some green noob like you about what I've been doing at the nunnery or wherever, 'aight?!","TWN":"一個沒負責過一件事情的毛頭小子，怎麼可能什麼事都隨便告訴你呢，社會生活可不是那麼容易的！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님, 그만하세요. 말씀이 지나쳐요.","JPN":"シスター・シンディ、やめてください。言いすぎです。","ENG":"That's enough, Sister Cindy. You go too far.","TWN":"姊妹，別再說了。妳話說得太過分了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"쟤가 자꾸 캐물으려고 하잖아. 왜 나만 갖고 그래.","JPN":"あいつが先に探りを入れてきたのに、なんでアタシばっかり。","ENG":"But the fool keeps trying to pry! Cut me some slack here.","TWN":"明明是他一直在追問，幹嘛說我。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"다른 사람 허물을 비난하기만 하는 건 신앙인으로서 안 될 짓이에요.","JPN":"他人の過ちを非難ばかりするのは、信仰者としてあるまじき行為です。","ENG":"A woman of faith should not focus on the flaws of others.","TWN":"一味指責別人的缺點，不是一個信徒該有的行為。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"계속 그러시면 약속했던 놀이공원은 안 보내 드릴 거예요?","JPN":"そういう態度を取り続けると、遊園地に連れて行ってあげませんよ？","ENG":"I won't take you to the amusement park as I promised if you keep this up, okay?","TWN":"妳要是再這樣，之前說好的遊樂園就不讓妳去了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"우씨이......","JPN":"ううっ……","ENG":"Aw...","TWN":"哼……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"죄송합니다. 자매님은 제가 잘 타이를게요.","JPN":"すみません。シスター・シンディには私がしっかり叱っておきます。","ENG":"I apologize. I'll be sure to set the young sister here on the right path.","TWN":"對不起，我會好好教導我的姊妹的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......아니. 맞는 말이긴 해.","JPN":"……いや、本当のことだ。","ENG":"No... She's actually right, you know.","TWN":"……不，她說得沒錯。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네? 갑자기 무슨 말씀이세요?","JPN":"え？　どういうことですか？","ENG":"Pardon? What do you mean?","TWN":"嗯？你這是什麼意思？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뒷골목 깡패들도 그래. 깜냥이 모자란 녀석한테는 중요한 건을 안 알려 줘.","JPN":"路地裏のチンピラだってそうだ。責任の取れないやつには、大事な話をしない。","ENG":"It's the same with the street thugs. They don't let you in on the sweet deals unless you've got the street cred.","TWN":"村子裡的小混混也是這樣，他們不會將重要的事情告訴沒本事的傢伙。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"인정하긴 싫지만...... 내 주제엔 감당 못할 일이라고 생각했던 거겠지.","JPN":"認めたくないが……俺は半人前ってことだろ。","ENG":"As much as I'd hate to admit... She must've figured I don't have what it takes to deal with the truth.","TWN":"雖然不想承認……但想來是他們覺得憑我的能力，沒辦法承擔那些事吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야, 건방진 꼬맹아. 잘난 체 할 수 있을 때 실컷 해 둬.","JPN":"おい、そこの生意気なガキ。デカい口を叩けるのも今のうちだけだ。","ENG":"Listen, you little twerp. Enjoy your petty feeling of superiority while it lasts.","TWN":"喂，傲慢的小不點，要囂張就趁現在吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"다음에 만날 때는 나도 폼나는 조직에서 아주 많은 걸 책임지는 남자가 되어 있을 테니까.","JPN":"今度会う時は、俺もカッコいい組織で責任を持った、\\nいい男になってるはずだからな。","ENG":"Next time we meet, I'll be a man of great responsibility at a posh organization myself.","TWN":"因為下次再見時，我一定會成為某個強大組織中，一個真正有擔當的男人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"흥, 누구랑은 다르게 말귀는 잘 알아듣는 편이네.","JPN":"ふん、物分かりはいい方だね。","ENG":"Hmpf. At least you're quick to catch my drift... unlike someone else I know.","TWN":"哼，跟某人不一樣，還挺識趣的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 난 가 본다. 신부님 돌아오시면 인사나 전해 줘.","JPN":"じゃあな。神父が来たら、代わりによろしく伝えてくれ。","ENG":"I'll get going, then. Give the father my regards when he comes back.","TWN":"那我先走了，神父回來後代我向他問好。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"......근데 저 놈팡이, 헌금은 왜 안 내고 가?","JPN":"……ところでアイツ、献金は？","ENG":"Hang on, Prince Charming didn't pay his offering!","TWN":"……不過那傢伙怎麼不奉獻就走了？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님, 헌금은 자매님이 이상한 영화 사라고 받는 돈이 아니에요.","JPN":"シスター・シンディ。献金は、あなたが変な映画を買うためのお金ではありません。","ENG":"Sister Cindy, the offering isn't for you to take to purchase your morbid films.","TWN":"姊妹，奉獻不是為了讓妳買奇怪的電影才收的錢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"내 훌륭한 조언으로 방황하던 탕아가 정신 차렸잖아. 그럼 받을 만하지.","JPN":"アタシの素晴らしいアドバイスのおかげで、あの放蕩息子が自分の道を見つけたんだ。\\nだったら、献金をもらってもいいはずだろ。","ENG":"Come on, the prodigal son has come to his senses thanks to my sagacious advice. I deserve to wet my beak a little.","TWN":"我的好建議讓彷徨的浪子打起了精神，我當然有資格收錢了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그건 주님께서 자매님을 통해 저 분에게 은총을 내리신 거죠.","JPN":"主がシスター・シンディを通して、あの方に恵みをお与えになったんです。","ENG":"Or the Lord was simply using you to extend His grace unto that young man.","TWN":"那是主透過姊妹向那位先生賜下的恩典。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그리고 주님의 은총은 누구에게나 열려 있답니다.","JPN":"それに主の恵みは、すべての方に与えられるものですから。","ENG":"Besides, the Lord's grace is freely available to all His children.","TWN":"而且主的恩典始終面向所有人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"에휴. 상담비는 천당 가서 청구해야겠다.","JPN":"はあ、カウンセリング費用は天国でもらおう。","ENG":"Ugh... I guess I'd better send the Lord an invoice when I get to heaven.","TWN":"唉，看來諮詢費得去天堂申請了呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그보다 이제 어쩔 거야? 다음은 프리드웬인가 하는 애들이랑 만나러 간다며?","JPN":"それより、これからどうするの？\\n次は、プリドウェンだか何だかに会いに行くんでしょ？","ENG":"So what now? Weren't we supposed go meet those Prydwen guys or whomever?","TWN":"那現在該怎麼辦？不是說還要去見叫什麼普利多溫的人嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네, 벌써 시간이 이렇게 됐네요. 얼른 가 봐야겠어요.","JPN":"あら、もうこんな時間ですか。急ぎましょう。","ENG":"Oh, you're right. Look at the time. We'd better hurry.","TWN":"對，時間不早了。我們得趕快走了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};